('computer-science:2-2-3a-string-manipulation:fib:6bb0c95e', 'computer-science', 'computer-science:2-2-3a-string-manipulation', '2.2.3a String Manipulation', 'fib', 'fib', 1, '{"question": "str.upper converts every letter in a string to _____ case.", "blankOptions": {"B1": ["code", "Concatenation", "upper", "65"]}}'::jsonb, '{"blanks": {"B1": "upper"}}'::jsonb),
